# MPEG2TS 동영상 파일 로드 및 화면 표시 방법

NXDL 프레임워크를 사용하여 MPEG2TS 파일을 로드하고 화면에 표시하는 방법을 안내해 드립니다.

## 1. 주요 클래스 구조

```
XVideoIO      → 비디오 입출력 관리
XVideo        → 비디오 스트리밍 처리
XVideoChannel → 스트리밍 파싱 및 프레임 데이터 관리
```

## 2. 기본 구현 예제 (WPF)

### [grounding-required].cs

```csharp
using System;
using System.Windows;
using Pixoneer.XDL;
using Pixoneer.XVideo;

namespace XDL_VideoView1
{
    public partial class MainWindow : Window
    {
        XVideoIO m_VideoIO;          // Video 입출력 객체
        XVideo m_Video;              // 비디오 스트리밍 처리 객체
        XVideoChannel m_channel;     // 스트리밍 채널 (MPEG2TS는 MultiChannel 지원)

        public MainWindow()
        {
            InitializeComponent();
            m_VideoIO = new XVideoIO();
        }

        private void openFileMenuItem_Click(object sender, RoutedEventArgs e)
        {
            // 파일 선택 다이얼로그
            var dialog = new Microsoft.Win32.OpenFileDialog
            {
                Filter = "MPEG2TS Files|*.ts;*.m2ts;*.mpeg2ts|All Files|*.*"
            };

            if (dialog.ShowDialog() == true)
            {
                LoadVideoFile(dialog.FileName);
            }
        }

        private void LoadVideoFile(string filePath)
        {
            try
            {
                // 1. 비디오 IO 객체로 파일 로드
                m_Video = m_VideoIO.LoadFile(filePath);

                // 2. 채널 정보 확인 (MPEG2TS는 여러 채널 가능)
                if (m_Video != null)
                {
                    m_channel = m_Video.GetChannel(0); // 첫 번째 채널 선택

                    // 3. 화면에 표시 (VideoView 컨트롤에 바인딩)
                    videoViewControl.Source = m_channel;

                    // 4. 재생 시작
                    m_Video.Play();
                }
            }
            catch (Exception ex)
            {
                MessageBox.Show($"파일 로드 실패: {ex.Message}");
            }
        }

        private void Window_Closing(object sender, System.ComponentModel.CancelEventArgs e)
        {
            // 리소스 정리
            if (m_Video != null)
            {
                m_Video.Stop();
                m_Video.Dispose();
            }
            if (m_VideoIO != null)
            {
                m_VideoIO.Dispose();
            }
        }
    }
}
```

### [grounding-required]

```xml
<Window x:Class="XDL_VideoView1.MainWindow"
        xmlns="http://schemas.microsoft.com/winfx/2006/xaml/presentation"
        xmlns:x="http://schemas.microsoft.com/winfx/2006/xaml"
        Title="MPEG2TS Player" Height="600" Width="800">
    <Grid>
        <Grid.RowDefinitions>
            <RowDefinition Height="Auto"/>
            <RowDefinition Height="*"/>
        </Grid.RowDefinitions>

        <!-- 메뉴 바 -->
        <Menu Grid.Row="0">
            <MenuItem Header="파일">
                <MenuItem Header="열기" Click="openFileMenuItem_Click"/>
                <MenuItem Header="닫기" Click="closeFileMenuItem_Click"/>
            </MenuItem>
            <MenuItem Header="재생">
                <MenuItem Header="재생" Click="playMenuItem_Click"/>
                <MenuItem Header="일시정지" Click="pauseMenuItem_Click"/>
                <MenuItem Header="정지" Click="stopMenuItem_Click"/>
            </MenuItem>
        </Menu>

        <!-- 비디오 표시 영역 -->
        <Border Grid.Row="1" Background="Black">
            <XVideoView x:Name="videoViewControl" 
                        Stretch="Uniform"/>
        </Border>
    </Grid>
</Window>
```

## 3. 재생 제어 기능

```csharp
private void playMenuItem_Click(object sender, RoutedEventArgs e)
{
    if (m_Video != null)
        m_Video.Play();
}

private void pauseMenuItem_Click(object sender, RoutedEventArgs e)
{
    if (m_Video != null)
        m_Video.Pause();
}

private void stopMenuItem_Click(object sender, RoutedEventArgs e)
{
    if (m_Video != null)
        m_Video.Stop();
}

private void closeFileMenuItem_Click(object sender, RoutedEventArgs e)
{
    if (m_Video != null)
    {
        m_Video.Stop();
        m_Video.Dispose();
        m_Video = null;
        videoViewControl.Source = null;
    }
}
```

## 4. MPEG2TS 형식 지정 (필요시)

```csharp
// 명시적으로 MPEG2TS 형식으로 로드
m_Video = m_VideoIO.LoadFile(filePath, eVideoFormatType.MPEG2TS);
```

## 5. 주요 포인트

| 항목 | 설명 |
|------|------|
| **XVideoIO** | 파일 입출력 관리, LoadFile() 메서드 사용 |
| **XVideo** | 스트리밍 처리, Play/Pause/Stop 제어 |
| **XVideoChannel** | 개별 스트림 채널 관리 (MPEG2TS는 멀티채널 지원) |
| **eVideoFormatType** | MPEG2TS, MP4, AVI 등 형식 지정 |
| **Dispose** | 사용 후 반드시 리소스 정리 필요 |

## 6. 참고 사항

1. **MPEG2TS 특성**: 여러 프로그램/스트림을 포함할 수 있으므로 채널 선택이 중요
2. **리소스 관리**: 사용 후 반드시 `Dispose()` 호출하여 메모리 정리
3. **에러 처리**: 파일 로드 실패 시 예외 처리 필수
4. **UI 스레드**: 재생 제어는 UI 스레드에서 실행 권장

이 코드를 기반으로 MPEG2TS 파일을 로드하고 재생할 수 있습니다. 추가적인 기능(진행도 표시, 음량 조절 등)은 `XVideo` 클래스의 추가 메서드를 활용하여 구현할 수 있습니다.

