	NXImageEngine::NXImageEngine()
	{
		DesignMode = Xfn::DesignMode;
		if(DesignMode)	return;

		m_ImageViews = gcnew ArrayList();
		XDL::XString strError;
		m_pImageEngine = XImageEngine::Create(strError);
		if (m_pImageEngine) m_pImageEngine->Initialize();

		m_MessageFilter = gcnew NXImageMessageFilter();
	}

	NXImageEngine::~NXImageEngine()
	{
		this->!NXImageEngine();
	}

	NXImageEngine::!NXImageEngine()
	{
		if(DesignMode)		return;

		if(m_pImageEngine)
		{
			m_pImageEngine->Release();
			m_pImageEngine = nullptr;
		}
		int nNumofImageview = m_ImageViews->Count;
		for (int i=0; i<nNumofImageview ; i++)
		{
			NXImageView^ gcView = (NXImageView^)m_ImageViews[i];
			//gcView->m_ImageEngine = nullptr;
		}

		m_ImageViews->Clear();
	}

	bool NXImageEngine::AddImageView(NXImageView^% view)
	{
		if(DesignMode)		return true;
		if(!m_pImageEngine)	return false;

		if(m_ImageViews->Contains(view))
			return false;

		m_ImageViews->Add(view);

		NXImageView^ gcView = (NXImageView^)(m_ImageViews[m_ImageViews->Count-1]);

		HWND hwnd = (HWND)(void*)gcView->GetHandle();

