public enum class eCCErr : System::Int32
{
	/// <summary> plug-in 드라이버를 로딩할 수 없습니다. </summary>
	DriverNotLoaded					= XCCERR_DRIVER_NOT_LOADED,
	/// <summary> 성공. </summary>
	Success							= XCCERR_NONE,
	/// <summary> 데이터가 충분하지 않습니다. </summary>
	NotEnoughData					= XCCERR_NOT_ENOUGH_DATA,
	/// <summary> 메모리가 부족하여 할당할 수 없습니다. </summary>
	NotEnoughMemory					= XCCERR_NOT_ENOUGH_MEMORY,
	/// <summary> 해당 기하형식은 지원하지 않는다. </summary>
	UnsupportedGeometryType			= XCCERR_UNSUPPORTED_GEOMETRY_TYPE,
	/// <summary> 해당 작업은 지원하지 않는다. </summary>
	UnSupportedOperation			= XCCERR_UNSUPPORTED_OPERATION,
