/// <summary>
/// XSpatialReference는 공간 좌표 시스템에서 정의되는 파라미터를 설정하여 좌표변환에 사용된다.
/// 즉, 특정 투영법으로 투영된 영상의 공간 좌표계를 XSpatialReference객체를 통해 정의할 수 있다.
/// XSpatialReference는 OpenGIS Spatial Reference를 준수하며 Well Known Text 포맷 등을 지원한다.
/// </summary>
/// <example>
/// <span id="Example 1">
/// "WGS 84 / UTM zone 52N(northern hemisphere" 좌표계를 설정하고 이를 WKT 문자열로 가져오는 예제이다.
/// <code>
/// // Set to utm northern hemisphere 52 zone.
/// XSpatialReference sr = new XSpatialReference();
/// sr.SetWellKnownGeogCS("WGS84");
/// // sr.SetWellKnownGeoCS("EPGS:4326");
/// sr.SetUTM(52, true);
/// 
/// String strWkt= "";
/// sr.exportToWkt(ref strWkt);
/// 
/// </code>
/// </span>
/// </example>
public ref class XSpatialReference
{
internal:
	CC::XSpatialReference* m_pSR;

public:
	/// <summary> XSpatialReference객체에 기본 생성자로서, 멤버 변수들을 초기화한다. </summary>
	XSpatialReference();

	///// <summary> XSpatialReference객체에 대하여 외부 비관리객체의 포인터를 입력받아 복사하여 초기화한다. <br />C++ 인터페이스.</summary>
	///// <param name="pSR">C++ 원본 인스턴스</param>
	//XSpatialReference(CC::XSpatialReference* pSR);

	/// <summary> XSpatialReference객체에 대하여 외부 비관리객체의 포인터를 입력받아 복사하여 초기화한다. </summary>
	/// <param name="pSR">원본 인스턴스</param>
	XSpatialReference(IntPtr pSR);

	/// <summary> XSpatialReference객체에 대하여 외부 관리객체를 입력받아 복사하여 초기화한다.  </summary>
	/// <param name="a">초기화 값</param>
	XSpatialReference(const XSpatialReference^ a);

	~XSpatialReference();

/// <summary> Geographic 좌표 시스템인지 여부를 확인한다. </summary>
/// <returns> Geographic 좌표 시스템이면 true, 아니면 false를 리턴. </returns>
bool	IsGeographic();

/// <summary>  투영 좌표 시스템인지 여부를 확인한다.</summary>
/// <returns> 투영된 좌표 시스템이면 true, 아니면 false를 리턴. </returns>
bool	IsProjected();

/// <summary> Geocentric 좌표 시스템(ECEF)인지 여부를 확인한다. </summary>
/// <returns> Geocentric 좌표 시스템이면 true, 아니면 false를 리턴. </returns>
bool	IsGeocentric();

/// <summary> Local좌표 시스템인지 여부를 확인한다. <br />
/// 좌표계는 통상 이용되는 범위에 따라 전지구적 차원에서사용되는 Global좌표계와 일부 지역(Local)에서만 사용하는 지역적 좌표계로 분류한다. </summary>
/// <returns> Local 좌표 시스템이면 true, 아니면 false를 리턴. </returns>
bool	IsLocal();

/// <summary> 좌표계 시스템이 동일한지 확인한다. </summary>
/// <param name = "sr">[In] 비교를 위한 인스턴스 </param>
/// <returns> 동일한 좌표 시스템이면 true, 아니면 false를 리턴. </returns>
bool	IsSame(XSpatialReference^ sr);

/// <summary> 
/// 자주 사용하는 좌표계를 문자열로 정의하여 좌표계를 초기화한다. <br />
/// <list type="bullet">
/// <item> <description> "WGS84" : "EPSG:4326" 와 동일</description></item>
/// <item> <description> "WGS72" : "EPSG:4322" 와 동일</description></item>
/// <item> <description> "NAD27" : "EPSG:4267" 와 동일</description></item>
/// <item> <description> "NAD83" : "EPSG:4269" 와 동일</description></item>
/// <item> <description> "EPSG:n" : ImportFromEPSG(n) 와 동일한 기능을 하는 Well Known Text.</description></item>
/// </list>
///</summary>
/// <param name = "strGeog">[In] Well Known Text 값. </param>
void	SetWellKnownGeogCS(String^ strGeog);

/// <summary> 입력 Zone 및 북반구 정보를 이용하여 UTM 좌표계를 설정한다. </summary>
/// <param name = "Zone">[In] UTM zone</param>
/// <param name = "bNorth">[In] 선정하는 영역이 북반구이면 true, 남반구이면 false를 입력. </param>
/// <returns> 에러 코드. </returns>
eCCErr		SetUTM(int Zone, bool bNorth);

/// <summary> 객체의 UTM Zone에 대한 정보를 획득한다. </summary>
/// <param name = "bNorth">[Out] 설정된 좌표계가 북반구 기준이면 true를, 남반구이면 false를 반환. </param>
/// <returns> UTM zone </returns>
int		GetUTMZone(bool% bNorth);

/// <summary> UTM 좌표 시스템인지를 확인한다. </summary>
/// <returns> UTM 좌표 시스템이면 true, 아니면 false를 리턴 </returns>
bool	IsUTM();

/// <summary> 이 객체와 동일한 XSpatialReference객체를 생성하여 반환한다. </summary>
/// <returns> 신규 XSpatialReference객체. </returns>
XSpatialReference^ Clone();

/// <summary>
/// 좌표체계의 유효 사용영역을 확인한다. 
/// </summary>
/// <param name="westLon">[Out] 최서단 경도값(단위 : degree). 	알 수 없는 경우에는 MAX_REAL64를 반환. </param>
/// <param name="southLat">[Out] 최남단 위도값(단위 : degree). 알 수 없는 경우에는 MAX_REAL64를 반환.</param>
/// <param name="eastLon">[Out] 최동단 경도값(단위 : degree). 	알 수 없는 경우에는 MAX_REAL64를 반환.</param>
/// <param name="northLat">[Out] 최북단 위도값(단위 : degree). 알 수 없는 경우에는 MAX_REAL64를 반환.</param>
/// <param name="strAreaName">[Out] 사용영역에 대한 설명</param>
/// <returns>성공하면 true를, 그렇지 않으면 false를 반환한다. </returns>
bool	GetAreaOfUse(double% westLon, double% southLat, double% eastLon, double% northLat, String^% strAreaName);

/// <summary>EPSG 코드에서 최적의 좌표체계를 찾아 EPSG 문자열을 반환한다. </summary>
/// <param name="nMinimumMatchConfidence">최소 적합 조건 <br />
/// 0~100 값이 유효하면 100인 경우 정확하게 맞는 EPSG 코드를 찾아서 반환한다. 0인 경우 90의 조건으로 검색한다.</param>
/// <returns>EPSG:0000 형태의 문자열. 찾을 수 없는 경우는 빈 문자열을 반환한다.</returns>
String^ FindBestEPSGMatch(int nMinimumMatchConfidence);

/// <param name = "elev"> [In] 기체를 기준으로 한 센서의 고각. </param>
/// <param name = "rollRelative"> [In] 기체에 상대적인 센서 가시선 방향의 회전각. </param>
/// <param name = "yaw"> [Out] 최종 센서의 yaw 각도. </param>
/// <param name = "pitch"> [Out] 최종 센서의 pitch 각도. </param>
/// <param name = "roll"> [Out] 최종 센서의 roll 각도. </param>
/// <returns> 기체의 중심점에서 센서가 향하는 방향 벡터. </returns>
static XVertex3d^ CalcGlobalSensorAttitudeInPlatformAxis3(XGeoPoint^ ptPos, XAngle^ yawPlatform, XAngle^ pitchPlatform, XAngle^ rollPlatform, XAngle^ azimuth, XAngle^ elev, XAngle^ rollRelative, XAngle^% yaw, XAngle^% pitch, XAngle^% roll);

/// <summary>
/// UAS LS 표준에 따라 지구 타원체 상의 특정 지점에서 지구 중심으로 향하는 축과 직교하는 좌표계(NED)에서 North 시선 방향인 기체와 센서의 회전각을 입력 받아서
/// D 방향을 지향하는 센서가 탑재된 N 방향 기준의 센서 자세를 나타내는 yaw, pitch, roll값을 계산한다.  <br />
/// 즉, 입력 지점에서 NED 축을 입력된 자세로 회전했을 때 센서의 시선은 N축과 일치하고,
/// 센서의 시선이 D축으로 정렬되는 자세 회전각을 계산한다.
/// </summary>
/// <param name = "ptPos"> [In] 기체/센서 위치 </param>
/// <param name = "yawPlatform"> [In] 기체 yaw 각도. </param>
/// <param name = "pitchPlatform"> [In] 기체 pitch 각도. </param>
/// <param name = "rollPlatform"> [In] 기체 roll 각도. </param>
/// <param name = "azimuthRelative"> [In] 기체를 기준으로한 센서의 방위각. </param>
/// <param name = "elevRelative"> [In] 기체를 기준으로 한 센서의 고각. 0이 정면, 음수가 아래 방향. </param>
/// <param name = "rollRelative"> [In] 센서 렌즈 축의 회전각. </param>
/// <param name = "yaw"> [Out] 최종 센서 프레임의 yaw 각도. </param>
/// <param name = "pitch"> [Out] 최종 센서 프레임의 pitch 각도. </param>
/// <param name = "roll"> [Out] 최종 센서 프레임의 roll 각도. </param>
/// <returns> 기체의 중심점에서 센서가 향하는 방향 벡터. </returns>
static XVertex3d^	CalcGlobalSensorAttitudeInPlatformUAS(XGeoPoint^ ptPos, XAngle^ yawPlatform, XAngle^ pitchPlatform, XAngle^ rollPlatform, XAngle^ azimuthRelative, XAngle^ elevRelative, XAngle^ rollRelative, XAngle^% yaw, XAngle^% pitch, XAngle^% roll);

/// <summary>
/// UAS LS 표준에 따라 지구 타원체 상의 특정 지점에서 지구 중심으로 향하는 축과 직교하는 좌표계(NED)에서 North 시선 방향인 기체와 센서의 회전각을 입력받아서
/// 기체 자세에 상대적인 센서의 자세 회전각을 계산한다.
/// </summary>
/// <param name = "yawPlatform"> [In] 기체 yaw 각도. </param>
/// <param name = "pitchPlatform"> [In] 기체 pitch 각도. </param>
/// <param name = "rollPlatform"> [In] 기체 roll 각도. </param>
/// <param name = "azimuthSensor"> [In] NED 기준 센서의 방위각. </param>
/// <param name = "elevSensor"> [In] NED 기준 센서의 고각. 0이 정면, 음수가 아래 방향. </param>
/// <param name = "rollSensor"> [In] 센서 렌즈 축의 회전각. </param>
/// <param name = "azimuthRelative"> [Out] 기체를 기준으로 한 센서의 방위각. </param>
/// <param name = "elevRelative"> [Out] 기체를 기준으로 한 센서의 고각. 0이 정면, 음수가 아래 방향. </param>
/// <param name = "rollRelative"> [Out] 센서 렌즈 축의 회전각. </param>
static void CalcRelativeSensorAttitudeInPlatformUAS(XAngle^ yawPlatform, XAngle^ pitchPlatform, XAngle^ rollPlatform, XAngle^ azimuthSensor, XAngle^ elevSensor, XAngle^ rollSensor, [OutAttribute] XAngle^% azimuthRelative, [OutAttribute] XAngle^% elevRelative, [OutAttribute] XAngle^% rollRelative);

/// <summary>
/// 투영 좌표계 원점의 ENU 좌표계를 기준으로 하는 카메라 회전각 omega, phi, kappa에 해당하는 센서 위치의 yaw, pitch, roll을 계산한다.
/// </summary>
/// <param name = "ptOrigin"> [In] 투영 좌표계 원점 위치. (예. Korea TM Center 127,38 / East 129,38 / West 125,38 / UTM-k 127.5,38) </param>
/// <param name = "omega"> [In] 카메라의 투영 좌표계 X축(E) 회전각. </param>
/// <param name = "phi"> [In] 카메라의 투영 좌표계 Y축(N) 회전각. </param>
/// <param name = "kappa"> [In] 카메라의 투영 좌표계 Z축(U) 회전각. </param>
/// <param name = "ptPos"> [In] 카메라 센서 위치. </param>
/// <param name = "bLookDown"> [In] 센서 회전 후 지향 방향이 하방(D)인 경우 참, 전방(N)인 경우 거짓. </param>
/// <param name = "yaw"> [Out] 센서 방위각. </param>
/// <param name = "pitch"> [Out] 센서 고각. </param>
/// <param name = "roll"> [Out] 센서 회전각. </param>
/// <returns> 센서 가시선 방향. Omega, phi, kappa 각도로 회전된 좌표축의 -Z 방향과 같다. </returns>
static XVertex3d^	OmegaPhiKappaToYawPitchRoll(XGeoPoint^ ptOrigin, XAngle^ omega, XAngle^ phi, XAngle^ kappa, XGeoPoint^ ptPos, bool bLookDown, [OutAttribute] XAngle^% yaw, [OutAttribute] XAngle^% pitch, [OutAttribute] XAngle^% roll);

/// <summary>
/// 센서 자세를 투영 좌표계 원점의 ENU 좌표계를 기준으로 하는 카메라 회전각 omega, phi, kappa로 변환한다.
