/// <param name = "kappa"> [Out] 카메라의 투영 좌표계 Z축(U) 회전각. </param>
/// <returns> 센서 가시선 방향. Omega, phi, kappa 각도로 회전된 좌표축의 -Z 방향과 같다. </returns>
static XVertex3d^	YawPitchRollToOmegaPhiKappa(XGeoPoint^ ptPos, XAngle^ yaw

/// <param name = "rollRelative"> [In] 센서 렌즈 축의 회전각. </param>
/// <param name = "yaw"> [Out] 최종 센서 프레임의 yaw 각도. </param>
/// <param name = "pitch"> [Out] 최종 센서 프레임의 pitch 각도. </param>
/// <param name = "roll"> [Out] 최종 센서 프레임의 roll 각도. </param>
/// <returns> 기체의 중심점에서 센서가 향하는 방향 벡터. </returns>
static XVertex3d^	CalcGlobalSensorAttitudeInPlatformUAS(XGeoPoint^ ptPos, XAngle^ yawPlatform, XAngle^ pitchPlatform, XAngle^ rollPlatform, XAngle^ azimuthRelative, XAngle^ elevRelative, XAngle^ rollRelative, XAngle^% yaw, XAngle^% pitch, XAngle^% roll);

/// <summary>
/// UAS LS 표준에 따라 지구 타원체 상의 특정 지점에서 지구 중심으로 향하는 축과 직교하는 좌표계(NED)에서 North 시선 방향인 기체와 센서의 회전각을 입력받아서
