static void CalcRelativeSensorAttitudeInPlatformUAS(XAngle^ yawPlatform, XAngle^ pitchPlatform, XAngle^ rollPlatform, XAngle^ azimuthSensor, XAngle^ elevSensor, XAngle^ rollSensor, [OutAttribute] XAngle^% azimuthRelative, [OutAttribute] XAngle^% elevRelative, [OutAttribute] XAngle^% rollRelative);

