XCoordinateTransformation::XCoordinateTransformation()
{
	m_pCT = nullptr;
}

XCoordinateTransformation::~XCoordinateTransformation()
{
	this->!XCoordinateTransformation();
}

XCoordinateTransformation::!XCoordinateTransformation()
{
	if (Xfn::LookupGCMapGeneric(System::IntPtr(m_pCT)))
	{
		Xfn::RemoveFromGCMapGeneric(System::IntPtr(m_pCT));

		if (m_pCT != nullptr) delete m_pCT;
		m_pCT = nullptr;
	}
}

bool XCoordinateTransformation::CreateCoordinateTransform(XSpatialReference^% SrIn, XSpatialReference^% SrOut)
{
	if (SrIn == nullptr || SrOut == nullptr) return false;
	if (SrIn->m_pSR == nullptr || SrOut->m_pSR == nullptr) return false;

	CC::XCoordinateTransformation* pCT = CC::Xcc::CreateCoordTrans(SrIn->m_pSR, SrOut->m_pSR);
	if (pCT == nullptr) return false;

	// Add Reference Count and register to Garbage collection map for new object
	Xfn::AddToGCMapGeneric(System::IntPtr(pCT));

	// Remove from Garbage collection map for old object
	if (m_pCT != nullptr) delete m_pCT;
	Xfn::RemoveFromGCMapGeneric(System::IntPtr(m_pCT));

	m_pCT = pCT;
	return true;
}

bool XCoordinateTransformation::TransformPt(double xIn, double yIn, double% xOut, double% yOut)
{
	if (m_pCT == nullptr) return false;

	double tmpx, tmpy;
	m_pCT->TransformPt(xIn, yIn, tmpx, tmpy);
	xOut = tmpx;
	yOut = tmpy;
	return true;
}

bool XCoordinateTransformation::TransformPt(double% x, double% y)
{
	if (m_pCT == nullptr) return false;
	double tmpx = x, tmpy = y;
	m_pCT->TransformPt(tmpx, tmpy);
	x = tmpx;
	y = tmpy;
	return true;
}

bool Xcc::WGP2UTM(NXDL::XAngle^ lon, NXDL::XAngle^ lat, NXDL::XVertex2d^% pos, int% Zone)
{
	double x, y;
	int izone;
	x = y = 0;
	izone = 0;

	bool bResult = CC::XCoordinateTransformation::WGP_TO_UTM(lon->deg, lat->deg, 2, x, y, izone);

	pos->x = x;
	pos->y = y;
	Zone = izone;

	return (bResult == true);
}
