	/// <param name="pMetad"> XDL 내부 형식의 메타데이터 비관리 객체 포인터. </param>
	/// <param name="pCapture"> XDL 내부 형식의 화면 갈무리버퍼 비관리 객체 포인터. 비디오 영상처리가 끝난 프레임을 갈무한다. </param>
	private delegate void XVideoPlaybackLayer_Event_OnRenderFrame_Inner(XDL::VD::XVideoPlaybackLayerBase* pLayer, XDL::VD::XFramePicture* pFrame, XDL::SM::XFrameSensor* pFrameSensor, XDL::VD::XMetadFrame* pMetad, XDL::GR::XFrameCaptureBuffer* pCapture);
	/// <summary> 동영상 재생 레이어에서 재생 시점의 프레임 자료를 넘겨 받는 이벤트 콜백 함수 대리자. </summary>
	/// <param name="sender"> 콜백 함수를 부르는 레이어. </param>
	/// <param name="frame"> 재생 중인 영상 프레임. </param>
	/// <param name="sensor"> 프레임 센서모델. </param>
