	public ref class NXImageLayerVideo : NXImage::NXImageLayer
	{
	private:
		XDL::VD::XImageLayerVideo* m_pNativeLayer;
		XVideoChannel^ m_VideoChannel;

		Color m_BlendColor;
		cli::array<float>^ m_Homography;
		cli::array<float>^ m_InvH;

	public:
		/// <summary> NXImageLayerVideo 객체를 생성하고 데이터 멤버를 초기화한다. 기본 생성자.</summary>
		NXImageLayerVideo();
		~NXImageLayerVideo() { this->!NXImageLayerVideo(); }
		!NXImageLayerVideo();

	public:	
		/// <summary> 레이어에서 표시할 영상 프레임을 설정한다. 동영상 채널이 먼저 설정된 경우 프레임 설정 요청은 무시된다. </summary>
		/// <param name="frame"> 표시할 영상 프레임. </param>
		void SetVideoFrame(XFramePicture^ frame);

		/// <summary> 레이어에서 표시할 동영상 채널을 설정한다. </summary>
		/// <param name="channel"> 표시할 동영상 채널. 입력 채널이 nullptr인 경우 기존 설정 채널을 제거한다. </param>
		void SetVideoChannel(XVideoChannel^ channel);

		/// <summary> 레이어에 연결된 채널을 제거한다. </summary>
		void ResetVideoChannel();

		/// <summary> 레이어에서 표시할 영상 프레임 크기를 설정한다. 
		/// 동영상 채널이 설정되어 있으면 이 요청은 무시되고 채널 동영상 크기로 자동 설정된다. </summary>
		/// <remarks> 채널과 동영상이 설정되지 않은 경우 GetBound()와 같은 연산을 위해 이 메소드를 통해 프레임 크기를 미리 지정할 필요가 있다. </remarks>
		/// <param name="width"> 표시할 영상 프레임 가로 크기. 0보다 큰 값이어야 한다. </param>
		/// <param name="height"> 표시할 영상 프레임 세로 크기. 0보다 큰 값이어야 한다. </param>
		void SetInitialFrameSize(int width, int height);

		/// <summary> 비디오 프레임의 채도(Saturation) 값을 설정한다. (원본 상태: 1.0, 권장 범위: 0~2) </summary>
		property float		VideoSaturation {float get(); void set(float val); }
		/// <summary> 비디오 프레임의 대조비(Contrast) 값을 설정한다. (원본 상태: 1.0, 권장 범위: 0~2) </summary>
		property float		VideoContrast {float get(); void set(float val); }

		/// <summary> 비디오 프레임의 감마 조정 인자를 설정한다. (기본값: 1.0) </summary>
		property float		VideoGammaFactor {float get(); void set(float val); }

		/// <summary> 비디오 프레임의 동적 명암비(HDR) 처리를 활성화한다. </summary>
		property bool		VideoHDR {bool get(); void set(bool val); }

		/// <summary> 비디오 프레임의 선명화 필터 강도(Sigma)를 설정한다. 0인 경우 필터를 해제한다. (권장 범위: 0~2, 기본값: 0.5) </summary>
		property float		VideoSharpenSigma {float get(); void set(float val); }

		/// <summary> 그래픽 쉐이더를 이용한 영상처리 필터를 설정한다. 최종 설정된 필터만 적용되며 None 값으로 필터를 해제한다. </summary>
		property eVideoFilterType VideoFilterType { void set(eVideoFilterType val); }
		/// <summary> 필터 적용시 Filter 크기를 설정한다. 필터 크기는 5 이하가 적당하다. </summary>
		property int		VideoFilterSize {int get(); void set(int val); }


#pragma endregion

		/// <summary> 동영상 프레임이 그려질 때 프레임 데이터를 넘겨주는 콜백 이벤트. </summary>
		event XVideoPlaybackLayer_Event_OnRenderFrame^ OnRenderFrame;
	private:
		XVideoPlaybackLayer_Event_OnRenderFrame_Inner^ OnRenderFrame_Inner;
		GCHandle gchRenderFrameInner;
		void Bridge_OnRenderFrame(XDL::VD::XVideoPlaybackLayerBase* pLayer, XDL::VD::XFramePicture* pFrame, XDL::SM::XFrameSensor* pFrameSensor, XDL::VD::XMetadFrame* pMetad, XDL::GR::XFrameCaptureBuffer* pCapture);

	};

