public enum class eStereoCompMode : System::Int32
{
	/// <summary> Anaglyph mode. </summary>
	Anaglyph	= XDMCOMPOSITE_STEREO_ANAGLYPH,
	/// <summary> Interleaved mode. </summary>
	Interleave  = XDMCOMPOSITE_STEREO_INTERLEAVE,
	/// <summary> Shutter Left.  </summary>
	ShutterL	= XDMCOMPOSITE_STEREO_SHUTTER_L,
	/// <summary> Shutter Right. </summary>
	ShutterR	= XDMCOMPOSITE_STEREO_SHUTTER_R
};

